import { useState, useEffect } from "react";
import "./CreateLogin.css";

/* =========================
   HELPERS
========================= */

// ✅ GUARANTEED VALID PASSWORD
const generatePassword = () => {
  const upper = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  const lower = "abcdefghijklmnopqrstuvwxyz";
  const number = "0123456789";
  const special = "@$!%*?&";
  const all = upper + lower + number + special;

  let password =
    upper[Math.floor(Math.random() * upper.length)] +
    lower[Math.floor(Math.random() * lower.length)] +
    number[Math.floor(Math.random() * number.length)] +
    special[Math.floor(Math.random() * special.length)];

  for (let i = password.length; i < 8; i++) {
    password += all[Math.floor(Math.random() * all.length)];
  }

  return password
    .split("")
    .sort(() => Math.random() - 0.5)
    .join("");
};

const isValidEmail = (email) =>
  /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

/* =========================
   COMPONENT
========================= */

function CreateLogin() {
  const [employees, setEmployees] = useState([]);
  const [users, setUsers] = useState([]);

  const [selectedEmp, setSelectedEmp] = useState("");
  const [username, setUsername] = useState("");
  const [designation, setDesignation] = useState("");

  /* =========================
        LOAD DATA
     ========================= */
  useEffect(() => {
    setEmployees(JSON.parse(localStorage.getItem("employees")) || []);
    setUsers(JSON.parse(localStorage.getItem("users")) || []);
  }, []);

  /* =========================
        SELECT EMPLOYEE
     ========================= */
  const handleSelect = (id) => {
    setSelectedEmp(id);

    const emp = employees.find((e) => String(e.id) === String(id));
    if (!emp) return;

    setDesignation(emp.designation || "employee");
    setUsername(emp.email || "");
  };

  /* =========================
        CREATE LOGIN
     ========================= */
  const handleCreate = () => {
    if (!selectedEmp) return alert("Please select an employee");
    if (!isValidEmail(username)) return alert("Invalid email format");

    const emp = employees.find((e) => String(e.id) === String(selectedEmp));
    if (!emp) return;

    const exists = users.some((u) => u.empId === emp.id);
    if (exists) return alert("Login already exists for this employee");

    const newPassword = generatePassword();

    const newUser = {
      empId: emp.id,
      name: emp.name,
      username,
      password: newPassword,
      role: "employee",
    };

    const updatedUsers = [...users, newUser];
    setUsers(updatedUsers);
    localStorage.setItem("users", JSON.stringify(updatedUsers));

    alert(
      `Login Created Successfully\n\nUsername: ${username}\nPassword: ${newPassword}`
    );
  };

  /* =========================
        RESET PASSWORD
     ========================= */
  const handleReset = (empId) => {
    const newPassword = generatePassword();

    const updatedUsers = users.map((u) =>
      u.empId === empId ? { ...u, password: newPassword } : u
    );

    setUsers(updatedUsers);
    localStorage.setItem("users", JSON.stringify(updatedUsers));

    alert(`Password Reset Successful\n\nNew Password: ${newPassword}`);
  };

  return (
    <div className="create-login-page">
      <h2>Create / Reset Login Credentials</h2>

      {/* ================= FORM ================= */}
      <div className="create-login-form">
        <select
          value={selectedEmp}
          onChange={(e) => handleSelect(e.target.value)}
        >
          <option value="">Select Employee</option>
          {employees.map((emp) => (
            <option key={emp.id} value={emp.id}>
              {emp.name}
            </option>
          ))}
        </select>

        <input type="text" value={designation} disabled />

        <input
          type="text"
          placeholder="Email / Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <input
          type="text"
          placeholder="Password will be auto-generated"
          disabled
        />

        <button className="create-login-btn" onClick={handleCreate}>
          Create Login
        </button>
      </div>

      {/* ================= TABLE ================= */}
      <div className="create-login-table-card">
        <table className="create-login-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Employee</th>
              <th>Username</th>
              <th>Role</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {users.length === 0 ? (
              <tr>
                <td colSpan="5" className="no-users">
                  No users created
                </td>
              </tr>
            ) : (
              users.map((u, i) => (
                <tr key={u.empId}>
                  <td>{i + 1}</td>
                  <td>{u.name}</td>
                  <td>{u.username}</td>
                  <td>{u.role}</td>
                  <td>
                    <button
                      className="reset-btn"
                      onClick={() => handleReset(u.empId)}
                    >
                      Reset Password
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default CreateLogin;
